import xml.etree.ElementTree as ET

def parse_xml(file_path):
    tree = ET.parse(file_path)
    root = tree.getroot()
    settings = {}
    for child in root:
        if child.tag == "setting":
            settings[child.attrib["name"]] = child.text
    return settings